//! Repository for BomOperation entities
//!
//! Originally generated by metaphor-schema; now **user-owned** — this exact path is declared under
//! `user_owned` in `metaphor.codegen.yaml`, so the generator skips it wholesale. The custom methods
//! below hold the hand-written BomOperation SQL (4-layer rule: services orchestrate, repos hold SQL).
//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<BomOperation, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use rust_decimal::Decimal;
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::entity::BomOperation;

/// Table name for BomOperation entities
pub const TABLE_NAME: &str = "manufacturing.bom_operations";

/// Repository for BomOperation entities.
///
/// All standard CRUD, soft-delete, pagination, and bulk methods are
/// provided automatically via `Deref` to `backbone_orm::GenericCrudRepository`.
pub struct BomOperationRepository(
    backbone_orm::GenericCrudRepository<BomOperation, backbone_orm::SoftDelete>,
);

impl std::ops::Deref for BomOperationRepository {
    type Target = backbone_orm::GenericCrudRepository<BomOperation, backbone_orm::SoftDelete>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl BomOperationRepository {
    /// Create a new repository instance.
    pub fn new(pool: PgPool) -> Self {
        Self(backbone_orm::GenericCrudRepository::new(pool, TABLE_NAME))
    }
}

/// The exact row a BOM-operation insert writes. `operating_cost` is already computed server-side by
/// the write service (`money(time_in_mins / 60 * hour_rate)`), not re-derived here.
pub struct NewBomOperationRow {
    pub id: Uuid,
    pub company_id: Uuid,
    pub bom_id: Uuid,
    pub operation_id: Uuid,
    pub workstation_id: Uuid,
    pub time_in_mins: Decimal,
    pub hour_rate: Decimal,
    pub operating_cost: Decimal,
}

/// Hand-written BomOperation SQL. Lives here (not in the write service) per the module's 4-layer rule.
impl BomOperationRepository {
    /// Insert one BOM operation.
    ///
    /// Takes the CALLER'S connection so the operation commits in the SAME transaction as its header.
    /// The caller binds the company on that connection (`bind_company_on`) before calling — don't
    /// re-bind. The explicit `company_id` bind (denormalized from the parent BOM) stays as
    /// defense-in-depth behind the RLS fence (ADR-0010 Decision A).
    pub async fn insert_operation(
        &self,
        conn: &mut sqlx::PgConnection,
        o: &NewBomOperationRow,
    ) -> Result<(), sqlx::Error> {
        sqlx::query(
            r#"INSERT INTO manufacturing.bom_operations
                 (id, company_id, bom_id, operation_id, workstation_id, time_in_mins, hour_rate, operating_cost)
               VALUES ($1,$2,$3,$4,$5,$6,$7,$8)"#,
        )
        .bind(o.id).bind(o.company_id).bind(o.bom_id).bind(o.operation_id).bind(o.workstation_id)
        .bind(o.time_in_mins).bind(o.hour_rate).bind(o.operating_cost)
        .execute(conn)
        .await?;
        Ok(())
    }
}

backbone_core::impl_crud_repository!(BomOperationRepository, BomOperation, soft_delete);
